// 場所ピンのカタログ。全アイコンの SVG パス + 既定ラベル + カテゴリの単一の真。
// 場所ピン追加 UI とアイコンレンダリングの両方がここを参照する。
//
// データ前提:
//  - key = DB の places.icon / trip_pin_options.icon に入る安定値。既存値（pin /
//    airport / lodging / food …）は legacy なので glyph 名（Material Symbols 名）と
//    別物。新規追加アイコンは key == glyph（MS 名）に揃える。
//  - glyph 自体はランタイムでは参照しない（path を直接インライン埋め込み）。
//    コメントとして残してあるだけ。
//
// SVG は Material Symbols Rounded FILL 24px。viewBox "0 -960 960 960"。

export type IconCategory =
  | "dining"
  | "daily"
  | "transit"
  | "accommodation"
  | "leisure"
  | "nature"
  | "culture"
  | "other";

export const ICON_CATEGORIES: IconCategory[] = [
  "dining",
  "daily",
  "transit",
  "accommodation",
  "leisure",
  "nature",
  "culture",
  "other",
];

export type IconCatalogEntry = {
  key: string;
  label: string;
  category: IconCategory;
  path: string;
  // アイコンピッカーの「未追加」表示用（Material Symbols Rounded の非塗り
  // グリフ）。塗り版とは Google 側で別デザインされた別パスデータ
  // （塗りパスを単純に線で縁取ったものではない）。
  outlinePath: string;
};

