const BY_KEY = new Map(ICON_CATALOG.map((e) => [e.key, e]));

export function getIcon(key: string): IconCatalogEntry | undefined {
  return BY_KEY.get(key);
}

export function getIconPath(key: string): string {
  return BY_KEY.get(key)?.path ?? BY_KEY.get("pin")!.path;
}

export function getIconOutlinePath(key: string): string {
  return BY_KEY.get(key)?.outlinePath ?? BY_KEY.get("pin")!.outlinePath;
}

export function getIconLabel(key: string): string {
  return BY_KEY.get(key)?.label ?? key;
}

